set names utf8mb4;
use educare;

delete from quiz_questions;
alter table quiz_questions auto_increment = 1;

insert into quiz_questions (
  slug,
  prompt,
  category,
  difficulty,
  question_type,
  options_json,
  correct_index,
  explanation,
  sort_order,
  is_active
) values
  ('quiz-bank-001', 'Khi cảm thấy buồn nhưng chưa rõ lý do, điều đầu tiên nên làm là gì?', 'Cảm xúc', 'Cơ bản', 'MULTIPLE_CHOICE', '["Dành vài phút gọi tên cảm xúc của mình","Tự trách bản thân vì yếu đuối","Bỏ qua hoàn toàn cảm giác đó","Đăng ngay lên mạng để xin phản ứng"]', 0, 'Gọi tên cảm xúc giúp bạn hiểu mình rõ hơn trước khi tìm cách xử lý.', 1, true),
  ('quiz-bank-002', 'Nếu tức giận khi bị hiểu lầm, cách phản ứng nào lành mạnh hơn?', 'Cảm xúc', 'Cơ bản', 'MULTIPLE_CHOICE', '["La lớn để xả hết bực bội","Tạm bình tĩnh rồi nói rõ điều mình muốn giải thích","Im lặng nhiều ngày để người khác tự hiểu","Nói lời làm tổn thương lại"]', 1, 'Bình tĩnh trước rồi giao tiếp rõ ràng giúp mâu thuẫn dễ được tháo gỡ hơn.', 2, true),
  ('quiz-bank-003', 'Dấu hiệu nào cho thấy bạn đang cần nghỉ ngơi về mặt cảm xúc?', 'Cảm xúc', 'Trung bình', 'MULTIPLE_CHOICE', '["Luôn thấy mọi chuyện đều nặng nề và dễ cáu gắt","Hôm nay học khá tốt","Muốn nghe nhạc yêu thích","Nhớ một kỷ niệm vui"]', 0, 'Cảm giác quá tải kéo dài là tín hiệu nên nghỉ ngơi và chăm sóc bản thân.', 3, true),
  ('quiz-bank-004', 'Khi một người bạn buồn, điều gì giúp họ cảm thấy được lắng nghe hơn?', 'Cảm xúc', 'Cơ bản', 'MULTIPLE_CHOICE', '["Ngắt lời để kể chuyện của mình","Đưa lời khuyên thật nhanh dù chưa hiểu rõ","Lắng nghe và hỏi xem họ cần gì","Bảo họ đừng buồn nữa"]', 2, 'Lắng nghe trước giúp người kia cảm thấy an toàn và được tôn trọng.', 4, true),
  ('quiz-bank-005', 'Viết nhật ký cảm xúc có ích vì lý do nào?', 'Cảm xúc', 'Trung bình', 'MULTIPLE_CHOICE', '["Giúp nhìn rõ điều gì đang ảnh hưởng đến mình","Biến mọi vấn đề thành nghiêm trọng hơn","Khiến mình phải suy nghĩ tiêu cực","Chỉ phù hợp với người lớn"]', 0, 'Viết ra giúp bạn nhận diện cảm xúc, tình huống và nhu cầu của mình.', 5, true),
  ('quiz-bank-006', 'Nếu vừa vui vừa lo trước một thay đổi mới, điều đó có bình thường không?', 'Cảm xúc', 'Cơ bản', 'MULTIPLE_CHOICE', '["Không, chỉ được có một cảm xúc","Có, nhiều cảm xúc có thể xuất hiện cùng lúc","Chỉ người yếu mới như vậy","Chỉ nên giữ lại cảm xúc tích cực"]', 1, 'Con người có thể trải nghiệm nhiều cảm xúc cùng lúc, nhất là trước thay đổi.', 6, true),
  ('quiz-bank-007', 'Khi thấy mình ghen tị với thành công của bạn bè, cách nghĩ nào lành mạnh hơn?', 'Cảm xúc', 'Trung bình', 'MULTIPLE_CHOICE', '["Mình kém cỏi hơn họ hoàn toàn","Cảm giác này nhắc mình xem điều gì mình cũng muốn cố gắng","Mình nên tránh hết những người giỏi","Mình phải tỏ ra không quan tâm"]', 1, 'Ghen tị có thể trở thành tín hiệu để hiểu điều mình mong muốn phát triển.', 7, true),
  ('quiz-bank-008', 'Điều gì giúp bạn bình tâm hơn khi lo lắng tăng cao?', 'Cảm xúc', 'Cơ bản', 'MULTIPLE_CHOICE', '["Nín thở lâu để quên cảm giác","Thở chậm và đưa sự chú ý về hiện tại","Ép mình không được lo nữa","Xem quá nhiều thông tin tiêu cực"]', 1, 'Thở chậm và chú ý vào hiện tại giúp cơ thể dịu lại.', 8, true),
  ('quiz-bank-009', 'Nếu một ngày tâm trạng xuống thấp, mục tiêu hợp lý nhất là gì?', 'Cảm xúc', 'Trung bình', 'MULTIPLE_CHOICE', '["Phải vui lên ngay lập tức","Chăm sóc mình bằng những việc nhỏ và an toàn","Làm như không có gì xảy ra","Tự cô lập hoàn toàn"]', 1, 'Những việc nhỏ như nghỉ ngơi, ăn uống và tâm sự có thể hỗ trợ rất nhiều.', 9, true),
  ('quiz-bank-010', 'Kỹ năng nào giúp bạn hiểu cảm xúc của mình tốt hơn theo thời gian?', 'Cảm xúc', 'Nâng cao', 'MULTIPLE_CHOICE', '["Quan sát hoàn cảnh, cơ thể và suy nghĩ đi kèm","Tránh nói về cảm xúc mãi mãi","Chỉ nghe người khác đánh giá mình","Luôn chờ cảm xúc tự biến mất"]', 0, 'Hiểu mối liên hệ giữa tình huống, suy nghĩ và cơ thể giúp bạn nhận diện cảm xúc tốt hơn.', 10, true),
  ('quiz-bank-011', 'Điều gì giúp bạn tự tin hơn khi bước vào một môi trường mới?', 'Tự tin', 'Cơ bản', 'MULTIPLE_CHOICE', '["Chuẩn bị trước vài thông tin và nhắc mình không cần hoàn hảo","So sánh mình với người nổi bật nhất","Im lặng hoàn toàn để khỏi mắc lỗi","Giả vờ biết tất cả mọi thứ"]', 0, 'Sự chuẩn bị vừa đủ và kỳ vọng thực tế giúp bạn tự tin hơn.', 11, true),
  ('quiz-bank-012', 'Khi mắc lỗi nhỏ trước đám đông, cách nghĩ nào có lợi hơn?', 'Tự tin', 'Cơ bản', 'MULTIPLE_CHOICE', '["Một lỗi nhỏ không định nghĩa toàn bộ con người mình","Mình thật tệ và ai cũng chê cười","Từ nay không nên thử nữa","Phải đổ lỗi cho ai đó"]', 0, 'Tự tin bền vững đến từ cách nhìn công bằng với chính mình.', 12, true),
  ('quiz-bank-013', 'Lý do nào khiến việc ghi nhận tiến bộ nhỏ trở nên quan trọng?', 'Tự tin', 'Trung bình', 'MULTIPLE_CHOICE', '["Vì nó giúp mình thấy nỗ lực có giá trị","Vì chỉ cần làm ít là đủ","Vì sẽ được khen nhiều hơn","Vì khỏi phải học điều mới"]', 0, 'Nhìn thấy tiến bộ nhỏ giúp xây dựng cảm giác mình có thể phát triển.', 13, true),
  ('quiz-bank-014', 'Khi sợ phát biểu trong lớp, bước khởi đầu hợp lý là gì?', 'Tự tin', 'Trung bình', 'MULTIPLE_CHOICE', '["Tập nói một ý ngắn trước","Ép mình nói thật dài ngay lần đầu","Nghĩ rằng mình chắc chắn sẽ thất bại","Trốn mọi tiết học cần trao đổi"]', 0, 'Bắt đầu từ bước nhỏ giúp giảm áp lực và tăng trải nghiệm thành công.', 14, true),
  ('quiz-bank-015', 'So sánh bản thân với phiên bản hôm qua của mình có ích vì sao?', 'Tự tin', 'Cơ bản', 'MULTIPLE_CHOICE', '["Giúp mình đo tiến bộ thực tế hơn","Làm mình cạnh tranh với người khác tốt hơn","Khiến mình luôn hài lòng","Giúp không cần học thêm gì"]', 0, 'So sánh với chính mình giúp bạn thấy rõ con đường phát triển phù hợp.', 15, true),
  ('quiz-bank-016', 'Câu nào thể hiện tự tin lành mạnh hơn?', 'Tự tin', 'Trung bình', 'MULTIPLE_CHOICE', '["Mình không cần ai góp ý nữa","Mình có điểm mạnh riêng và vẫn có thể học thêm","Mình phải giỏi hơn tất cả","Mình không được phép sai"]', 1, 'Tự tin lành mạnh đi cùng sự cởi mở học hỏi, không phải tự cho mình hoàn hảo.', 16, true),
  ('quiz-bank-017', 'Điều gì dễ làm tự tin giảm đi lâu dài?', 'Tự tin', 'Trung bình', 'MULTIPLE_CHOICE', '["Tự nói với mình toàn những lời hạ thấp","Xin hỗ trợ khi cần","Luyện tập đều đặn","Nhìn lại điểm mạnh của bản thân"]', 0, 'Những lời tự chê bai lặp lại có thể bào mòn lòng tin vào chính mình.', 17, true),
  ('quiz-bank-018', 'Khi được khen, phản ứng nào giúp bạn đón nhận lời khen tốt hơn?', 'Tự tin', 'Cơ bản', 'MULTIPLE_CHOICE', '["Phủ nhận ngay vì ngại","Cảm ơn và ghi nhận nỗ lực của mình","Đổi chủ đề thật nhanh","Cười nhạt rồi bỏ đi"]', 1, 'Đón nhận lời khen một cách bình tĩnh là cách củng cố cái nhìn tích cực về bản thân.', 18, true),
  ('quiz-bank-019', 'Vai trò của ngôn ngữ cơ thể với sự tự tin là gì?', 'Tự tin', 'Nâng cao', 'MULTIPLE_CHOICE', '["Không ảnh hưởng gì","Tư thế thẳng và hơi thở ổn định có thể giúp mình vững hơn","Chỉ cần quần áo đẹp là đủ","Phải luôn nhìn người khác thật lâu"]', 1, 'Cơ thể và tâm trí liên hệ với nhau, nên tư thế và hơi thở có thể hỗ trợ cảm giác tự tin.', 19, true),
  ('quiz-bank-020', 'Mục tiêu nào thực tế nhất khi rèn sự tự tin?', 'Tự tin', 'Cơ bản', 'MULTIPLE_CHOICE', '["Không bao giờ run nữa","Vẫn hành động dù còn hơi run","Làm ai cũng thích mình","Không cần luyện tập"]', 1, 'Tự tin không phải hết lo hoàn toàn mà là vẫn có thể tiến lên từng bước.', 20, true),
  ('quiz-bank-021', 'Khi bài vở nhiều khiến bạn rối, nên bắt đầu bằng cách nào?', 'Học tập', 'Cơ bản', 'MULTIPLE_CHOICE', '["Liệt kê việc cần làm và chọn việc quan trọng trước","Ngồi lo lắng thật lâu","Làm ngẫu nhiên việc nào cũng được","Bỏ hết để ngày mai tính"]', 0, 'Chia nhỏ nhiệm vụ giúp đầu óc bớt quá tải và dễ bắt đầu hơn.', 21, true),
  ('quiz-bank-022', 'Cách học nào thường hiệu quả hơn khi ôn một chủ đề khó?', 'Học tập', 'Trung bình', 'MULTIPLE_CHOICE', '["Đọc đi đọc lại mà không tự kiểm tra","Tự hỏi lại kiến thức bằng câu hỏi ngắn","Mở nhiều tab cùng lúc","Chỉ học khi thật có hứng"]', 1, 'Tự kiểm tra giúp não bộ ghi nhớ chủ động hơn.', 22, true),
  ('quiz-bank-023', 'Nếu cứ trì hoãn việc học vì sợ khó, bước nào phù hợp nhất?', 'Học tập', 'Cơ bản', 'MULTIPLE_CHOICE', '["Bắt đầu bằng 10 phút đầu tiên","Chờ đến khi hoàn toàn sẵn sàng","Ép học liền 5 tiếng","Xem mình là người lười biếng"]', 0, 'Bắt đầu ngắn giúp vượt qua lực cản ban đầu.', 23, true),
  ('quiz-bank-024', 'Lý do nên nghỉ ngắn giữa các phiên học là gì?', 'Học tập', 'Cơ bản', 'MULTIPLE_CHOICE', '["Giúp não bộ hồi lại và giữ tập trung tốt hơn","Làm mình quên hết kiến thức","Chỉ để giải trí","Vì học liên tục luôn có hại"]', 0, 'Nghỉ ngắn đúng lúc giúp duy trì sự tập trung và giảm mệt mỏi.', 24, true),
  ('quiz-bank-025', 'Khi điểm số chưa tốt, cách phản ứng nào có ích nhất cho lần sau?', 'Học tập', 'Trung bình', 'MULTIPLE_CHOICE', '["Xem lại phần mình chưa hiểu và điều chỉnh cách học","Kết luận mình không có khả năng","Giấu luôn kết quả và không nhìn lại","Chép đáp án của bạn bè lần sau"]', 0, 'Phân tích nguyên nhân cụ thể giúp bạn cải thiện thực sự.', 25, true),
  ('quiz-bank-026', 'Không gian học tập nào thường hỗ trợ tập trung hơn?', 'Học tập', 'Cơ bản', 'MULTIPLE_CHOICE', '["Nơi đủ sáng, gọn và ít xao nhãng","Mở nhiều video cùng lúc","Vừa học vừa lướt mạng liên tục","Chỗ quá tối để đỡ mỏi mắt"]', 0, 'Môi trường rõ ràng, đủ sáng và ít xao nhãng giúp học hiệu quả hơn.', 26, true),
  ('quiz-bank-027', 'Nếu vừa học vừa thấy đầu óc không vào, nên thử điều gì trước?', 'Học tập', 'Trung bình', 'MULTIPLE_CHOICE', '["Đổi sang một mục tiêu nhỏ hơn hoặc nghỉ ngắn","Tự ép đến khi kiệt sức","Bỏ hẳn việc học nhiều ngày","So sánh mình với người khác"]', 0, 'Điều chỉnh nhịp học thực tế giúp bạn quay lại hiệu quả hơn.', 27, true),
  ('quiz-bank-028', 'Việc hỏi thầy cô hay bạn bè khi không hiểu bài thể hiện điều gì?', 'Học tập', 'Cơ bản', 'MULTIPLE_CHOICE', '["Thiếu năng lực","Chủ động học và biết tìm hỗ trợ","Làm phiền người khác vô ích","Không tự lập"]', 1, 'Tìm trợ giúp đúng lúc là kỹ năng học tập tích cực.', 28, true),
  ('quiz-bank-029', 'Một kế hoạch học tốt thường có đặc điểm nào?', 'Học tập', 'Trung bình', 'MULTIPLE_CHOICE', '["Rõ mục tiêu, có thời gian nghỉ và đủ linh hoạt","Càng kín lịch càng tốt","Không cần ưu tiên gì cả","Chỉ tập trung vào môn dễ"]', 0, 'Kế hoạch hiệu quả cần rõ ràng nhưng vẫn có khoảng thở và khả năng điều chỉnh.', 29, true),
  ('quiz-bank-030', 'Điều gì giúp giảm áp lực trước kỳ kiểm tra?', 'Học tập', 'Nâng cao', 'MULTIPLE_CHOICE', '["Ôn đều từ sớm và giữ sinh hoạt ổn định","Thức trắng đêm ôn phút cuối","Tự dọa mình phải hoàn hảo","Đọc đáp án ngay trước giờ vào phòng"]', 0, 'Ôn đều và ngủ nghỉ hợp lý giúp bạn vào bài thi với trạng thái vững hơn.', 30, true),
  ('quiz-bank-031', 'Giấc ngủ đủ quan trọng với tuổi teen vì lý do nào?', 'Sức khỏe', 'Cơ bản', 'MULTIPLE_CHOICE', '["Giúp não bộ, cảm xúc và cơ thể phục hồi","Chỉ để không bị buồn ngủ trong lớp","Không liên quan đến tâm trạng","Chỉ cần ngủ bù cuối tuần là đủ"]', 0, 'Giấc ngủ ảnh hưởng trực tiếp đến học tập, cảm xúc và sức khỏe tổng thể.', 31, true),
  ('quiz-bank-032', 'Khi bỏ bữa sáng thường xuyên, điều gì dễ xảy ra?', 'Sức khỏe', 'Cơ bản', 'MULTIPLE_CHOICE', '["Dễ mệt, khó tập trung hơn","Thông minh hơn vì bụng nhẹ","Ngủ ngon hơn ngay lập tức","Tự nhiên cao nhanh hơn"]', 0, 'Bỏ bữa có thể khiến cơ thể thiếu năng lượng cho học tập và sinh hoạt.', 32, true),
  ('quiz-bank-033', 'Thói quen nào hỗ trợ sức khỏe tinh thần mỗi ngày?', 'Sức khỏe', 'Cơ bản', 'MULTIPLE_CHOICE', '["Dành thời gian vận động nhẹ và nghỉ ngơi hợp lý","Lướt điện thoại tới khuya","Giữ mọi áp lực trong lòng","Bỏ hoàn toàn các mối quan hệ tích cực"]', 0, 'Vận động và nghỉ ngơi điều độ giúp tinh thần ổn định hơn.', 33, true),
  ('quiz-bank-034', 'Khi cơ thể có dấu hiệu mệt kéo dài, điều nên làm là gì?', 'Sức khỏe', 'Trung bình', 'MULTIPLE_CHOICE', '["Quan sát thêm và nói với người lớn hoặc chuyên gia khi cần","Mặc kệ vì chắc tự hết","Tự dùng thuốc theo lời đồn","Cố hoạt động nhiều hơn để quên mệt"]', 0, 'Lắng nghe cơ thể và tìm hỗ trợ đúng lúc là điều quan trọng.', 34, true),
  ('quiz-bank-035', 'Uống đủ nước giúp ích điều gì?', 'Sức khỏe', 'Cơ bản', 'MULTIPLE_CHOICE', '["Hỗ trợ cơ thể hoạt động và giảm mệt mỏi","Làm thay được việc ăn uống","Không ảnh hưởng gì rõ rệt","Chỉ cần khi chơi thể thao"]', 0, 'Nước cần thiết cho nhiều hoạt động cơ bản của cơ thể trong ngày.', 35, true),
  ('quiz-bank-036', 'Nếu stress làm bạn đau đầu và khó ngủ, điều nào nên thử trước?', 'Sức khỏe', 'Trung bình', 'MULTIPLE_CHOICE', '["Sắp xếp lại nhịp sinh hoạt và tìm người tin cậy để chia sẻ","Uống nước ngọt liên tục","Cố thức thêm để làm việc cho xong","Tránh nói với bất kỳ ai"]', 0, 'Căng thẳng kéo dài cần được nhìn nhận và điều chỉnh bằng thói quen lành mạnh.', 36, true),
  ('quiz-bank-037', 'Tập thể dục phù hợp với tuổi teen nên được hiểu như thế nào?', 'Sức khỏe', 'Cơ bản', 'MULTIPLE_CHOICE', '["Là vận động đều đặn phù hợp thể trạng, không cần quá cực đoan","Phải luyện rất nặng mới có ích","Chỉ cần khi muốn giảm cân","Không liên quan đến tinh thần"]', 0, 'Điều quan trọng là sự đều đặn và phù hợp, không phải cực đoan.', 37, true),
  ('quiz-bank-038', 'Điều gì giúp hạn chế mệt mỏi do dùng màn hình quá lâu?', 'Sức khỏe', 'Trung bình', 'MULTIPLE_CHOICE', '["Nghỉ mắt định kỳ và thay đổi tư thế","Tăng độ sáng tối đa liên tục","Ngồi yên một tư thế nhiều giờ","Càng khuya càng dùng dễ tập trung"]', 0, 'Cho mắt và cơ thể nghỉ định kỳ giúp giảm mỏi và khó chịu.', 38, true),
  ('quiz-bank-039', 'Khi nghe lời khuyên về sức khỏe trên mạng, nên làm gì?', 'Sức khỏe', 'Nâng cao', 'MULTIPLE_CHOICE', '["Kiểm tra nguồn đáng tin cậy trước khi làm theo","Tin ngay nếu nhiều người chia sẻ","Thử hết mọi cách càng sớm càng tốt","Chỉ nghe người nổi tiếng"]', 0, 'Thông tin sức khỏe cần được kiểm tra kỹ để tránh gây hại.', 39, true),
  ('quiz-bank-040', 'Một thói quen ăn uống cân bằng có nghĩa là gì?', 'Sức khỏe', 'Cơ bản', 'MULTIPLE_CHOICE', '["Đa dạng thực phẩm và không cực đoan với bản thân","Nhịn hẳn món mình thích","Chỉ ăn một nhóm thực phẩm mỗi ngày","Ăn thật ít để dễ kiểm soát"]', 0, 'Cân bằng là đa dạng, điều độ và phù hợp với nhu cầu cơ thể.', 40, true),
  ('quiz-bank-041', 'Khi bất đồng với bố mẹ, mục tiêu tốt nhất của cuộc trò chuyện là gì?', 'Gia đình', 'Cơ bản', 'MULTIPLE_CHOICE', '["Hiểu nhau rõ hơn và tìm điểm chung","Phải thắng bằng mọi giá","Làm đối phương im lặng","Tránh nói chuyện mãi mãi"]', 0, 'Trong gia đình, hiểu nhau thường quan trọng hơn việc ai thắng ai.', 41, true),
  ('quiz-bank-042', 'Nếu muốn bố mẹ hiểu áp lực của mình, cách mở lời nào phù hợp hơn?', 'Gia đình', 'Trung bình', 'MULTIPLE_CHOICE', '["Con muốn chia sẻ để cả nhà hiểu con hơn","Bố mẹ chẳng bao giờ hiểu gì cả","Con không nói nữa đâu","Ai cũng đang làm con khó chịu"]', 0, 'Một cách mở lời bình tĩnh giúp cuộc trò chuyện dễ tiếp tục hơn.', 42, true),
  ('quiz-bank-043', 'Điều gì giúp xây dựng niềm tin trong gia đình?', 'Gia đình', 'Cơ bản', 'MULTIPLE_CHOICE', '["Trao đổi trung thực và giữ lời trong khả năng của mình","Giấu mọi chuyện để đỡ bị hỏi","Chỉ nói khi bị phát hiện","Nổi nóng để người khác sợ"]', 0, 'Niềm tin lớn dần từ những hành động đáng tin và sự trung thực.', 43, true),
  ('quiz-bank-044', 'Nếu người lớn góp ý làm bạn khó chịu, phản ứng nào lành mạnh hơn?', 'Gia đình', 'Trung bình', 'MULTIPLE_CHOICE', '["Xin thời gian bình tĩnh rồi trao đổi lại","Cắt ngang và bỏ đi ngay","Giữ ấm ức nhiều ngày nhưng không nói","Đáp trả bằng lời gây tổn thương"]', 0, 'Xin thời gian bình tĩnh giúp giảm xung đột và nói chuyện rõ hơn sau đó.', 44, true),
  ('quiz-bank-045', 'Trong gia đình, việc lắng nghe có vai trò gì?', 'Gia đình', 'Cơ bản', 'MULTIPLE_CHOICE', '["Giúp mỗi người cảm thấy mình được tôn trọng","Chỉ để nghe cho có","Không cần nếu người kia lớn tuổi hơn","Chỉ cần khi xảy ra cãi nhau"]', 0, 'Lắng nghe là nền tảng để hiểu cảm xúc và nhu cầu của nhau.', 45, true),
  ('quiz-bank-046', 'Nếu trong nhà có căng thẳng kéo dài, bạn nên ưu tiên điều gì?', 'Gia đình', 'Nâng cao', 'MULTIPLE_CHOICE', '["Giữ an toàn cho mình và tìm người lớn đáng tin để hỗ trợ","Tự chịu đựng hoàn toàn một mình","Ghi âm đăng lên mạng cho mọi người xem","Bỏ học để tránh về nhà"]', 0, 'An toàn và hỗ trợ phù hợp luôn là ưu tiên khi môi trường gia đình quá căng thẳng.', 46, true),
  ('quiz-bank-047', 'Một cách thể hiện quan tâm trong gia đình là gì?', 'Gia đình', 'Cơ bản', 'MULTIPLE_CHOICE', '["Hỏi han và hỗ trợ nhau bằng việc nhỏ mỗi ngày","Chờ đến khi có việc lớn mới nói chuyện","Giữ khoảng cách hoàn toàn","Chỉ quan tâm khi cần nhờ vả"]', 0, 'Sự quan tâm bền vững thường đến từ những việc nhỏ hằng ngày.', 47, true),
  ('quiz-bank-048', 'Khi muốn xin thêm quyền tự chủ, điều gì giúp lời đề nghị dễ được lắng nghe hơn?', 'Gia đình', 'Trung bình', 'MULTIPLE_CHOICE', '["Trình bày rõ lý do và cho thấy mình có trách nhiệm","Nổi nóng để tạo áp lực","So sánh bố mẹ với nhà khác","Bỏ qua mọi quy ước hiện tại"]', 0, 'Sự rõ ràng và trách nhiệm làm tăng khả năng được tin tưởng.', 48, true),
  ('quiz-bank-049', 'Nếu người thân đang mệt và cáu, điều gì có thể giúp không khí dịu lại?', 'Gia đình', 'Trung bình', 'MULTIPLE_CHOICE', '["Chọn thời điểm khác để nói chuyện quan trọng","Ép họ trả lời ngay","Đáp lại bằng giọng lớn hơn","Coi như mình phải chịu lỗi hết"]', 0, 'Chọn đúng thời điểm giúp cuộc nói chuyện có cơ hội tích cực hơn.', 49, true),
  ('quiz-bank-050', 'Bài học quan trọng khi sống cùng gia đình là gì?', 'Gia đình', 'Cơ bản', 'MULTIPLE_CHOICE', '["Khác biệt quan điểm không có nghĩa là hết yêu thương","Ai cũng phải nghĩ giống nhau","Im lặng là cách tốt nhất cho mọi vấn đề","Tình cảm chỉ có khi không xung đột"]', 0, 'Gia đình vẫn có thể gắn bó dù có lúc khác nhau về cách nghĩ.', 50, true),
  ('quiz-bank-051', 'Một tình bạn lành mạnh thường có đặc điểm nào?', 'Tình bạn', 'Cơ bản', 'MULTIPLE_CHOICE', '["Tôn trọng, lắng nghe và không ép buộc nhau","Luôn kiểm soát nhau mọi lúc","Phải giống nhau hoàn toàn","Chỉ vui khi có lợi ích"]', 0, 'Tình bạn lành mạnh dựa trên sự tôn trọng và an toàn.', 51, true),
  ('quiz-bank-052', 'Nếu bạn bè rủ làm điều khiến bạn không thoải mái, bạn nên làm gì?', 'Tình bạn', 'Cơ bản', 'MULTIPLE_CHOICE', '["Nói rõ mình không muốn tham gia","Làm theo để khỏi bị chê","Im lặng chịu đựng","Rủ thêm người khác cùng làm"]', 0, 'Nói rõ ranh giới là cách bảo vệ bản thân và mối quan hệ lành mạnh.', 52, true),
  ('quiz-bank-053', 'Khi bạn thân có chuyện riêng, cách cư xử phù hợp là gì?', 'Tình bạn', 'Cơ bản', 'MULTIPLE_CHOICE', '["Giữ kín nếu không liên quan đến an toàn","Kể lại cho nhóm để xin ý kiến","Đem ra đùa cho nhẹ không khí","Dùng làm điểm yếu khi giận nhau"]', 0, 'Tôn trọng sự riêng tư giúp nuôi dưỡng niềm tin.', 53, true),
  ('quiz-bank-054', 'Dấu hiệu nào cho thấy một mối quan hệ bạn bè có thể không lành mạnh?', 'Tình bạn', 'Trung bình', 'MULTIPLE_CHOICE', '["Bạn thường xuyên thấy mình bị ép và có lỗi vô lý","Cả hai cùng vui khi gặp nhau","Hai người biết xin lỗi khi cần","Có lúc khác ý nhưng vẫn tôn trọng nhau"]', 0, 'Cảm giác bị ép buộc và thao túng là tín hiệu cần chú ý.', 54, true),
  ('quiz-bank-055', 'Khi xảy ra hiểu lầm với bạn, điều gì nên làm trước?', 'Tình bạn', 'Trung bình', 'MULTIPLE_CHOICE', '["Hỏi lại để hiểu đúng trước khi kết luận","Đăng trạng thái mỉa mai","Nói xấu với người khác","Cắt đứt ngay không giải thích"]', 0, 'Làm rõ thông tin trước giúp tránh làm căng vấn đề không cần thiết.', 55, true),
  ('quiz-bank-056', 'Một người bạn tốt không có nghĩa là người đó phải như thế nào?', 'Tình bạn', 'Cơ bản', 'MULTIPLE_CHOICE', '["Luôn đồng ý với mình mọi chuyện","Biết lắng nghe","Tôn trọng cảm xúc của mình","Có thể góp ý khi cần"]', 0, 'Bạn tốt không phải lúc nào cũng đồng ý, mà là chân thành và tôn trọng.', 56, true),
  ('quiz-bank-057', 'Nếu thấy mình luôn mệt sau khi chơi với một nhóm bạn, điều đó có thể nói lên điều gì?', 'Tình bạn', 'Nâng cao', 'MULTIPLE_CHOICE', '["Mối quan hệ đó có thể đang không phù hợp hoặc thiếu an toàn","Mình bắt buộc phải cố hòa nhập hơn","Đó là chuyện bình thường nên bỏ qua","Mình không xứng đáng có bạn"]', 0, 'Cảm giác kiệt sức kéo dài là tín hiệu nên xem lại chất lượng mối quan hệ.', 57, true),
  ('quiz-bank-058', 'Khi một người bạn thành công, phản ứng nào giúp tình bạn đẹp hơn?', 'Tình bạn', 'Cơ bản', 'MULTIPLE_CHOICE', '["Chúc mừng họ chân thành","Lảng tránh vì thấy tự ti","Nói rằng họ chỉ gặp may","So sánh bản thân thật gay gắt"]', 0, 'Chúc mừng chân thành giúp duy trì sự tích cực trong tình bạn.', 58, true),
  ('quiz-bank-059', 'Điều gì giúp kết bạn mới tự nhiên hơn?', 'Tình bạn', 'Trung bình', 'MULTIPLE_CHOICE', '["Bắt đầu từ một câu hỏi đơn giản và sự chân thành","Tỏ ra hoàn hảo mọi lúc","Nói thật nhiều về mình ngay lập tức","Đợi người khác làm hết"]', 0, 'Sự chân thành và cởi mở vừa phải thường tạo cảm giác dễ gần.', 59, true),
  ('quiz-bank-060', 'Khi bạn bè trêu chọc quá mức, cách phản hồi nào phù hợp?', 'Tình bạn', 'Trung bình', 'MULTIPLE_CHOICE', '["Nói rõ rằng điều đó làm mình không thoải mái","Cười cho qua dù rất buồn","Trả đũa bằng điều nặng nề hơn","Im lặng mãi để không mất bạn"]', 0, 'Gọi tên điều khiến bạn khó chịu giúp người khác hiểu ranh giới của bạn.', 60, true),
  ('quiz-bank-061', 'Khi nhận được đường link lạ yêu cầu đăng nhập tài khoản, bạn nên làm gì?', 'An toàn trên mạng', 'Cơ bản', 'MULTIPLE_CHOICE', '["Không bấm vào khi chưa xác minh nguồn","Đăng nhập thử xem có gì","Gửi tiếp cho bạn bè cùng kiểm tra","Nhập mật khẩu cũ cho đỡ lo"]', 0, 'Không mở link lạ là bước cơ bản để tránh mất tài khoản.', 61, true),
  ('quiz-bank-062', 'Thông tin nào không nên công khai trên mạng xã hội?', 'An toàn trên mạng', 'Cơ bản', 'MULTIPLE_CHOICE', '["Địa chỉ nhà và lịch trình riêng","Một sở thích của bạn","Tên bài hát yêu thích","Màu sắc bạn thích"]', 0, 'Thông tin riêng tư có thể ảnh hưởng trực tiếp đến an toàn cá nhân.', 62, true),
  ('quiz-bank-063', 'Một mật khẩu mạnh thường có đặc điểm nào?', 'An toàn trên mạng', 'Cơ bản', 'MULTIPLE_CHOICE', '["Khó đoán và khác nhau giữa các tài khoản","Chỉ gồm ngày sinh cho dễ nhớ","Giống nhau hết cho tiện","Càng ngắn càng tốt"]', 0, 'Mật khẩu mạnh cần khó đoán và không dùng chung nhiều nơi.', 63, true),
  ('quiz-bank-064', 'Nếu bị mạo danh trên mạng, việc nên làm đầu tiên là gì?', 'An toàn trên mạng', 'Trung bình', 'MULTIPLE_CHOICE', '["Lưu bằng chứng và báo cáo tài khoản giả","Mặc kệ vì rồi sẽ tự hết","Tạo tài khoản khác để cãi lại","Đăng số điện thoại của người kia"]', 0, 'Lưu bằng chứng giúp bạn xử lý sự việc rõ ràng và an toàn hơn.', 64, true),
  ('quiz-bank-065', 'Tại sao nên cẩn trọng với ảnh hoặc tin nhắn đã gửi?', 'An toàn trên mạng', 'Trung bình', 'MULTIPLE_CHOICE', '["Vì nội dung số có thể bị lưu lại hoặc chia sẻ tiếp","Vì gửi rồi thì luôn biến mất","Vì chỉ người tốt mới xem được","Vì mạng xã hội luôn tự bảo vệ mình"]', 0, 'Nội dung số rất dễ bị lưu và lan truyền ngoài ý muốn.', 65, true),
  ('quiz-bank-066', 'Nếu ai đó nhắn tin đe dọa khiến bạn sợ hãi, bạn nên làm gì?', 'An toàn trên mạng', 'Nâng cao', 'MULTIPLE_CHOICE', '["Lưu lại bằng chứng và nói với người lớn đáng tin","Xóa ngay và giữ kín một mình","Gửi lời đe dọa lại","Chấp nhận yêu cầu của họ"]', 0, 'Trong tình huống đe dọa, bạn cần hỗ trợ thật thay vì đối đầu một mình.', 66, true),
  ('quiz-bank-067', 'Cài đặt quyền riêng tư trên ứng dụng giúp ích điều gì?', 'An toàn trên mạng', 'Cơ bản', 'MULTIPLE_CHOICE', '["Giúp bạn kiểm soát ai xem và ai liên hệ với mình","Tăng tốc mạng cho điện thoại","Tự chặn hết mọi nguy cơ","Làm tài khoản nổi bật hơn"]', 0, 'Quyền riêng tư tốt giúp bạn chủ động hơn trong việc chia sẻ.', 67, true),
  ('quiz-bank-068', 'Khi quen một người chỉ qua mạng và họ muốn gặp riêng, điều gì là an toàn hơn?', 'An toàn trên mạng', 'Nâng cao', 'MULTIPLE_CHOICE', '["Nói với người lớn đáng tin và không đi một mình","Đi ngay để chứng minh mình dũng cảm","Giấu gia đình để khỏi bị cấm","Chỉ cần nhắn vị trí sau khi tới nơi"]', 0, 'Các cuộc gặp ngoài đời cần sự chuẩn bị và hỗ trợ từ người lớn đáng tin.', 68, true),
  ('quiz-bank-069', 'Điều gì nên làm khi xem thấy thử thách nguy hiểm đang lan truyền trên mạng?', 'An toàn trên mạng', 'Trung bình', 'MULTIPLE_CHOICE', '["Không làm theo và tránh chia sẻ tiếp","Thử một lần cho biết","Quay video tham gia cho vui","Rủ thêm bạn cùng làm"]', 0, 'Không tham gia và không lan truyền giúp giảm nguy cơ cho mình và người khác.', 69, true),
  ('quiz-bank-070', 'Một tài khoản đáng nghi thường có dấu hiệu nào?', 'An toàn trên mạng', 'Trung bình', 'MULTIPLE_CHOICE', '["Hối thúc cung cấp thông tin riêng hoặc tiền bạc","Có ảnh đại diện rõ ràng","Nhắn hỏi thăm lịch sự","Có tên tài khoản ngắn"]', 0, 'Sự thúc ép bất thường là dấu hiệu bạn cần cảnh giác.', 70, true),
  ('quiz-bank-071', 'Ranh giới cá nhân có nghĩa là gì?', 'Ranh giới cá nhân', 'Cơ bản', 'MULTIPLE_CHOICE', '["Những điều mình thấy an toàn và không thoải mái cần được tôn trọng","Luôn từ chối tất cả mọi người","Làm theo người khác để hòa hợp","Không bao giờ thay đổi ý kiến"]', 0, 'Ranh giới cá nhân giúp bạn biết điều gì phù hợp với mình.', 71, true),
  ('quiz-bank-072', 'Nếu ai đó đụng chạm khiến bạn khó chịu, phản ứng nào phù hợp?', 'Ranh giới cá nhân', 'Cơ bản', 'MULTIPLE_CHOICE', '["Nói dừng lại và lùi về khoảng cách an toàn","Cố chịu để khỏi mất lòng","Cười cho qua rồi im lặng","Tự trách mình quá nhạy cảm"]', 0, 'Bạn có quyền nói không với mọi hành vi khiến mình không thoải mái.', 72, true),
  ('quiz-bank-073', 'Một câu nói thể hiện ranh giới rõ ràng là gì?', 'Ranh giới cá nhân', 'Cơ bản', 'MULTIPLE_CHOICE', '["Mình không thoải mái với điều này","Thôi cũng được, tùy bạn hết","Chắc do mình khó tính quá","Sao cũng xong"]', 0, 'Câu nói rõ ràng giúp người khác hiểu giới hạn của bạn.', 73, true),
  ('quiz-bank-074', 'Điều gì không phải là dấu hiệu của một mối quan hệ tôn trọng ranh giới?', 'Ranh giới cá nhân', 'Trung bình', 'MULTIPLE_CHOICE', '["Liên tục ép bạn thay đổi quyết định","Lắng nghe khi bạn nói không","Tôn trọng không gian riêng","Hỏi ý kiến trước khi chạm vào đồ của bạn"]', 0, 'Ép buộc lặp lại cho thấy ranh giới của bạn không được tôn trọng.', 74, true),
  ('quiz-bank-075', 'Tại sao việc luyện nói không lại quan trọng?', 'Ranh giới cá nhân', 'Trung bình', 'MULTIPLE_CHOICE', '["Giúp bạn tự bảo vệ mình trong nhiều tình huống","Khiến người khác ghét mình","Chỉ dành cho người lạnh lùng","Không có tác dụng gì thực tế"]', 0, 'Biết từ chối đúng lúc là kỹ năng tự bảo vệ quan trọng.', 75, true),
  ('quiz-bank-076', 'Nếu thấy khó nói không trực tiếp, bước khởi đầu nào dễ hơn?', 'Ranh giới cá nhân', 'Trung bình', 'MULTIPLE_CHOICE', '["Tập một câu ngắn rõ ràng trước gương hoặc với người tin cậy","Cố làm hài lòng người khác trước","Đợi đến khi chịu không nổi mới nói","Nhắn những câu mơ hồ rồi hy vọng người kia tự hiểu"]', 0, 'Tập trước giúp bạn bớt run và rõ ràng hơn khi cần nói thật.', 76, true),
  ('quiz-bank-077', 'Một người tôn trọng ranh giới của bạn thường sẽ làm gì?', 'Ranh giới cá nhân', 'Cơ bản', 'MULTIPLE_CHOICE', '["Dừng lại khi bạn từ chối hoặc bày tỏ khó chịu","Cố thuyết phục thêm cho đến khi bạn đồng ý","Chế giễu giới hạn của bạn","Gây áp lực để bạn thấy có lỗi"]', 0, 'Sự tôn trọng thể hiện ở việc biết dừng đúng lúc.', 77, true),
  ('quiz-bank-078', 'Khi chính bạn lỡ vượt ranh giới của người khác, điều nên làm là gì?', 'Ranh giới cá nhân', 'Trung bình', 'MULTIPLE_CHOICE', '["Xin lỗi, dừng lại và điều chỉnh hành vi","Giải thích thật nhiều để biện minh","Nói họ quá nhạy cảm","Lặp lại vì nghĩ không nghiêm trọng"]', 0, 'Nhận lỗi và điều chỉnh là cách ứng xử trưởng thành.', 78, true),
  ('quiz-bank-079', 'Điều gì giúp bạn nhận ra ranh giới của bản thân rõ hơn?', 'Ranh giới cá nhân', 'Nâng cao', 'MULTIPLE_CHOICE', '["Chú ý đến cảm giác khó chịu, căng thẳng hoặc bị ép buộc","Chỉ làm theo số đông","Bỏ qua tín hiệu cơ thể","Chờ người khác quyết định hộ"]', 0, 'Cơ thể và cảm xúc thường báo trước khi ranh giới bị chạm tới.', 79, true),
  ('quiz-bank-080', 'Ranh giới cá nhân là cố định hoàn toàn hay có thể thay đổi theo thời gian?', 'Ranh giới cá nhân', 'Cơ bản', 'MULTIPLE_CHOICE', '["Có thể thay đổi khi bạn hiểu mình hơn","Phải giữ y nguyên mãi mãi","Không hề cần thiết","Chỉ có khi bạn lớn tuổi"]', 0, 'Ranh giới có thể thay đổi khi trải nghiệm và nhu cầu của bạn thay đổi.', 80, true),
